extension WebViewViewController: WKScriptMessageHandler {
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let body = message.body as? [String: Any] else { return }
        
        switch message.name {
        case "camera":
            handleCameraRequest(body)
        case "pushNotifications":
            handlePushNotificationRequest(body)
        case "inAppPurchase":
            handleInAppPurchaseRequest(body)
        case "nativeLog":
            handleNativeLog(body)
        default:
            break
        }
    }
    
    private func handleCameraRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "requestPermission":
            requestCameraPermission()
        case "openCamera":
            openCamera(data)
        default:
            break
        }
    }
    
    private func requestCameraPermission() {
        AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
            DispatchQueue.main.async {
                let result = ["granted": granted]
                self?.sendMessageToWeb("cameraPermissionResult", data: result)
            }
        }
    }
    
    private func openCamera(_ data: [String: Any]) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        guard status == .authorized else {
            sendMessageToWeb("cameraError", data: ["error": "Permission not granted"])
            return
        }
        
        let sourceType = data["sourceType"] as? String ?? "camera"
        
        guard UIImagePickerController.isSourceTypeAvailable(sourceType == "library" ? .photoLibrary : .camera) else {
            sendMessageToWeb("cameraError", data: ["error": "Source type not available"])
            return
        }
        
        let picker = UIImagePickerController()
        picker.delegate = self
        picker.sourceType = sourceType == "library" ? .photoLibrary : .camera
        picker.allowsEditing = data["allowsEditing"] as? Bool ?? false
        
        present(picker, animated: true)
    }
    
    private func handlePushNotificationRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "requestPermission":
            requestPushNotificationPermission()
        case "getToken":
            getPushNotificationToken()
        default:
            break
        }
    }
    
    private func requestPushNotificationPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.sendMessageToWeb("pushNotificationError", data: ["error": error.localizedDescription])
                } else {
                    self?.sendMessageToWeb("pushPermissionResult", data: ["granted": granted])
                    if granted {
                        UIApplication.shared.registerForRemoteNotifications()
                    }
                }
            }
        }
    }
    
    private func getPushNotificationToken() {
        if let token = UserDefaults.standard.string(forKey: "deviceToken") {
            sendMessageToWeb("pushTokenResult", data: ["token": token])
        } else {
            sendMessageToWeb("pushTokenResult", data: ["token": NSNull()])
        }
    }
    
    private func handleInAppPurchaseRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "purchase":
            guard let productId = data["productId"] as? String else { return }
            purchaseProduct(productId: productId)
        case "restore":
            restorePurchases()
        case "getProducts":
            guard let productIds = data["productIds"] as? [String] else { return }
            fetchProducts(productIds: productIds)
        default:
            break
        }
    }
    
    private func purchaseProduct(productId: String) {
        InAppPurchaseManager.shared.purchase(productId: productId) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let transaction):
                    self?.sendMessageToWeb("purchaseSuccess", data: [
                        "productId": productId,
                        "transactionId": transaction.transactionIdentifier ?? ""
                    ])
                case .failure(let error):
                    self?.sendMessageToWeb("purchaseError", data: ["error": error.localizedDescription])
                }
            }
        }
    }
    
    private func restorePurchases() {
        InAppPurchaseManager.shared.restorePurchases { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let transactions):
                    let transactionData = transactions.map { [
                        "productId": $0.payment.productIdentifier,
                        "transactionId": $0.transactionIdentifier ?? ""
                    ]}
                    self?.sendMessageToWeb("restoreSuccess", data: ["transactions": transactionData])
                case .failure(let error):
                    self?.sendMessageToWeb("restoreError", data: ["error": error.localizedDescription])
                }
            }
        }
    }
    
    private func fetchProducts(productIds: [String]) {
        InAppPurchaseManager.shared.fetchProducts(productIds: productIds) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let products):
                    let productData = products.map { [
                        "productId": $0.productIdentifier,
                        "title": $0.localizedTitle,
                        "description": $0.localizedDescription,
                        "price": $0.price.stringValue,
                        "priceLocale": $0.priceLocale.currencyCode ?? ""
                    ]}
                    self?.sendMessageToWeb("productsResult", data: ["products": productData])
                case .failure(let error):
                    self?.sendMessageToWeb("productsError", data: ["error": error.localizedDescription])
                }
            }
        }
    }
    
    private func handleNativeLog(_ data: [String: Any]) {
        if let message = data["message"] as? String {
            print("[WebView Log]: \(message)")
        }
    }
    
    private func sendMessageToWeb(_ event: String, data: [String: Any]) {
        do {
            let jsonData = try JSONSerialization.data(withJSONObject: data, options: [])
            if let jsonString = String(data: jsonData, encoding: .utf8) {
                let script = "window.dispatchEvent(new CustomEvent('\(event)', { detail: \(jsonString) }));"
                webView.evaluateJavaScript(script)
            }
        } catch {
            print("Error serializing data: \(error)")
        }
    }
}

