extension WebViewViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        picker.dismiss(animated: true)
        
        var image: UIImage?
        if let editedImage = info[.editedImage] as? UIImage {
            image = editedImage
        } else if let originalImage = info[.originalImage] as? UIImage {
            image = originalImage
        }
        
        guard let selectedImage = image else {
            sendMessageToWeb("cameraError", data: ["error": "No image selected"])
            return
        }
        
        if let imageData = selectedImage.jpegData(compressionQuality: 0.8) {
            let base64String = imageData.base64EncodedString()
            sendMessageToWeb("cameraResult", data: [
                "image": "data:image/jpeg;base64,\(base64String)",
                "width": selectedImage.size.width,
                "height": selectedImage.size.height
            ])
        }
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        picker.dismiss(animated: true)
        sendMessageToWeb("cameraCancelled", data: [:])
    }
}

